use std::sync::Arc;
use swc_common::{FileName, SourceMap, GLOBALS, Globals, Mark, sync::Lrc};
use swc_ecma_parser::{lexer::Lexer, Parser, StringInput, Syntax, TsSyntax};
use swc_ecma_ast::*;
use swc_ecma_visit::{Visit, VisitWith};
use swc_ecma_codegen::{text_writer::JsWriter, Emitter};
use swc_ecma_transforms_typescript::typescript;
use serde::Serialize;
use wasm_bindgen::prelude::*;

#[derive(Serialize)]
pub struct BettiValidationResult {
    pub is_valid: bool,
    pub error: Option<String>,
    pub ast_json: Option<String>,
}

struct BettiValidator {
    pub is_valid: bool,
    pub error_msg: Option<String>,
}

impl BettiValidator {
    fn new() -> Self {
        Self {
            is_valid: true,
            error_msg: None,
        }
    }

    fn report_error(&mut self, msg: &str) {
        if self.is_valid {
            self.is_valid = false;
            self.error_msg = Some(msg.to_string());
        }
    }

    /// Applies only to **exported** gnode bridge entrypoints. Internal helpers, nested functions,
    /// and top-level side-effect scripts are intentionally not validated here.
    fn validate_module_exports(&mut self, module: &Module) {
        for item in &module.body {
            if let ModuleItem::ModuleDecl(decl) = item {
                self.validate_module_decl(decl);
            }
        }
    }

    fn validate_module_decl(&mut self, decl: &ModuleDecl) {
        match decl {
            ModuleDecl::ExportDecl(ExportDecl { decl, .. }) => {
                if let Decl::Fn(fn_decl) = decl {
                    self.validate_fn_decl(fn_decl, "export declaration");
                }
            }
            ModuleDecl::ExportDefaultDecl(ExportDefaultDecl { decl, .. }) => {
                if let DefaultDecl::Fn(fn_expr) = decl {
                    self.validate_fn_expr(fn_expr, "export default");
                }
            }
            ModuleDecl::ExportDefaultExpr(ExportDefaultExpr { expr, .. }) => {
                if let Expr::Fn(fn_expr) = &**expr {
                    self.validate_fn_expr(fn_expr, "export default expression");
                }
            }
            _ => {}
        }
    }

    fn validate_fn_decl(&mut self, n: &FnDecl, label: &str) {
        let name = n.ident.sym.to_string();
        self.validate_function(&n.function, &name, label);
    }

    fn validate_fn_expr(&mut self, n: &FnExpr, label: &str) {
        let name = n
            .ident
            .as_ref()
            .map(|i| i.sym.to_string())
            .unwrap_or_else(|| "<anonymous>".to_string());
        self.validate_function(&n.function, &name, label);
    }

    fn validate_function(&mut self, function: &Function, name: &str, label: &str) {
        let is_entrypoint = name == "main" || name == "handler" || name == "app" || name == "default" || name == "<anonymous>";
        if !is_entrypoint {
            return;
        }

        if function.params.len() > 1 {
            self.report_error(&format!(
                "Gnosis TS bridge — entrypoint `{name}` ({label}): at most one parameter is allowed.\n\
                 Hint: `gnode run` passes at most one JSON input to the entrypoint."
            ));
            return;
        }

        for param in &function.params {
            if !param.pat.is_ident() {
                self.report_error(&format!(
                    "Gnosis TS bridge — entrypoint `{name}` ({label}): parameters must be simple identifiers (no destructuring)."
                ));
                return;
            }
        }

        let mut return_count = 0;
        if let Some(body) = &function.body {
            for stmt in &body.stmts {
                if stmt.is_return_stmt() {
                    return_count += 1;
                }
            }
        }

        if return_count == 0 {
            self.report_error(&format!(
                "Gnosis TS bridge — entrypoint `{name}` ({label}): the exported function body must contain exactly one `return` statement.\n\
                 Void / implicit-undefined returns are rejected for bridge entrypoints.\n\
                 Remediation: return an exit code number, a string payload, or structured JSON; or move work into non-exported helpers and keep the entrypoint as a single `return`.\n\
                 Note: non-exported top-level functions and nested callbacks are not subject to this rule.\n\
                 Source byte offset (function span lo): {}",
                function.span.lo.0
            ));
        } else if return_count > 1 {
            self.report_error(&format!(
                "Gnosis TS bridge — entrypoint `{name}` ({label}): at most one `return` statement is supported in the entrypoint body."
            ));
        }
    }
}

impl Visit for BettiValidator {
    fn visit_program(&mut self, program: &Program) {
        match program {
            Program::Module(module) => {
                self.validate_module_exports(module);
            }
            Program::Script(_) => {
                // Script-mode sources (no `import` / `export` syntax) do not declare ESM entrypoints.
            }
        }
    }
}

#[wasm_bindgen]
pub fn validate_and_parse_typescript(source_text: &str) -> JsValue {
    let cm: Arc<SourceMap> = Default::default();
    let fm = cm.new_source_file(FileName::Custom("bridge.ts".into()).into(), source_text.to_string());
    let lexer = Lexer::new(
        Syntax::Typescript(Default::default()),
        Default::default(),
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let program = match parser.parse_program() {
        Ok(p) => p,
        Err(e) => {
            let result = BettiValidationResult {
                is_valid: false,
                error: Some(format!("Parse error {:?}", e.into_kind())),
                ast_json: None,
            };
            return serde_wasm_bindgen::to_value(&result).unwrap();
        }
    };
    
    let mut validator = BettiValidator::new();
    program.visit_with(&mut validator);

    if !validator.is_valid {
        let result = BettiValidationResult {
            is_valid: false,
            error: validator.error_msg,
            ast_json: None,
        };
        return serde_wasm_bindgen::to_value(&result).unwrap();
    }

    // Pass the raw AST json to JS
    let ast_json = serde_json::to_string(&program).unwrap();

    let result = BettiValidationResult {
        is_valid: true,
        error: None,
        ast_json: Some(ast_json),
    };

    serde_wasm_bindgen::to_value(&result).unwrap()
}

#[derive(Serialize)]
pub struct ImportSpecifier {
    pub value: String,
    pub start: u32,
    pub end: u32,
}

struct ImportExtractor {
    pub imports: Vec<ImportSpecifier>,
}

impl Visit for ImportExtractor {
    fn visit_import_decl(&mut self, n: &ImportDecl) {
        self.imports.push(ImportSpecifier {
            value: n.src.value.to_string_lossy().into_owned(),
            start: n.src.span.lo.0 - 1, // swc spans are 1-indexed (BytePos)
            end: n.src.span.hi.0 - 1,
        });
        n.visit_children_with(self);
    }

    fn visit_named_export(&mut self, n: &NamedExport) {
        if let Some(src) = &n.src {
            self.imports.push(ImportSpecifier {
                value: src.value.to_string_lossy().into_owned(),
                start: src.span.lo.0 - 1,
                end: src.span.hi.0 - 1,
            });
        }
        n.visit_children_with(self);
    }
    
    fn visit_export_all(&mut self, n: &ExportAll) {
        self.imports.push(ImportSpecifier {
            value: n.src.value.to_string_lossy().into_owned(),
            start: n.src.span.lo.0 - 1,
            end: n.src.span.hi.0 - 1,
        });
        n.visit_children_with(self);
    }

    fn visit_call_expr(&mut self, n: &CallExpr) {
        if let Callee::Import(_) = &n.callee {
            if let Some(arg) = n.args.first() {
                if let Expr::Lit(Lit::Str(s)) = &*arg.expr {
                    self.imports.push(ImportSpecifier {
                        value: s.value.to_string_lossy().into_owned(),
                        start: s.span.lo.0 - 1,
                        end: s.span.hi.0 - 1,
                    });
                }
            }
        }
        n.visit_children_with(self);
    }
}

#[wasm_bindgen]
pub fn extract_imports(source_text: &str) -> JsValue {
    let cm: Arc<SourceMap> = Default::default();
    let fm = cm.new_source_file(FileName::Custom("bridge.ts".into()).into(), source_text.to_string());
    let lexer = Lexer::new(
        Syntax::Typescript(Default::default()),
        Default::default(),
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let program = match parser.parse_program() {
        Ok(p) => p,
        Err(_) => return JsValue::NULL,
    };
    
    let mut extractor = ImportExtractor { imports: Vec::new() };
    program.visit_with(&mut extractor);

    serde_wasm_bindgen::to_value(&extractor.imports).unwrap()
}

#[derive(Serialize)]
pub struct TranspileResult {
    pub code: String,
    pub error: Option<String>,
}

/// Native SWC TypeScript → JavaScript transpiler.
/// Strips TypeScript types and emits ESM JavaScript.
/// This replaces esbuild's `transform` function in the ggbuild pipeline.
#[wasm_bindgen]
pub fn transpile_typescript(source_text: &str, jsx: bool) -> JsValue {
    let cm: Lrc<SourceMap> = Default::default();
    let fm = cm.new_source_file(
        FileName::Custom("input.ts".into()).into(),
        source_text.to_string(),
    );

    let ts_syntax = TsSyntax {
        tsx: jsx,
        decorators: true,
        ..Default::default()
    };

    let lexer = Lexer::new(
        Syntax::Typescript(ts_syntax),
        EsVersion::Es2022,
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let mut program = match parser.parse_program() {
        Ok(p) => p,
        Err(e) => {
            let result = TranspileResult {
                code: String::new(),
                error: Some(format!("Parse error: {:?}", e.into_kind())),
            };
            return serde_wasm_bindgen::to_value(&result).unwrap();
        }
    };

    // Strip TypeScript types using SWC's typescript transform.
    GLOBALS.set(&Globals::new(), || {
        let unresolved_mark = Mark::new();
        let top_level_mark = Mark::new();
        let mut pass = typescript::strip(unresolved_mark, top_level_mark);
        pass.process(&mut program);
    });

    // Emit JavaScript using SWC's codegen.
    let mut buf = Vec::new();
    {
        let wr = JsWriter::new(cm.clone(), "\n", &mut buf, None);
        let mut emitter = Emitter {
            cfg: swc_ecma_codegen::Config::default()
                .with_target(EsVersion::Es2022)
                .with_ascii_only(false)
                .with_minify(false),
            cm: cm.clone(),
            comments: None,
            wr: Box::new(wr),
        };

        if let Err(e) = emitter.emit_program(&program) {
            let result = TranspileResult {
                code: String::new(),
                error: Some(format!("Codegen error: {e}")),
            };
            return serde_wasm_bindgen::to_value(&result).unwrap();
        }
    }

    let code = String::from_utf8(buf).unwrap_or_default();

    let result = TranspileResult { code, error: None };
    serde_wasm_bindgen::to_value(&result).unwrap()
}
